#include <stdio.h>
#include <stdlib.h>
int cmp_desc(const void *a, const void *b) {
    return *(int*)b - *(int*)a;
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, X; scanf("%d %d", &N, &X);
        int *a = (int*)malloc(N * sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &a[i]);
        qsort(a, N, sizeof(int), cmp_desc);
        int sum=0, ans=-1;
        for(int i=0;i<N;i++){
            sum+=a[i];
            if(sum>=X){ ans=i+1; break; }
        }
        printf("%d\n", ans);
        free(a);
    }
    return 0;
}

